import{_ as t,a as o,b as a,c as d,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as s,o as c,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Other/ocr.md","filePath":"th-TH/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"th-TH/Other/ocr.md"};function u(h,e,g,m,b,y){return c(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR ดึง text ออกจาก images, scans และ document screenshots</p><p>หลัง recognition แล้ว คุณสามารถ copy result, export เป็น <code>Markdown</code>, <code>PDF</code> หรือ <code>Word</code> หรือ package หลาย formats รวมกันเพื่อ download</p><h2 id="ocr-ทําอะไรได้บ้าง" tabindex="-1">OCR ทำอะไรได้บ้าง <a class="header-anchor" href="#ocr-ทําอะไรได้บ้าง" aria-label="Permalink to &quot;OCR ทำอะไรได้บ้าง&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Image text recognition</td><td>Extract text จาก images, screenshots และ scans</td></tr><tr><td>Document layout recognition</td><td>เหมาะกับ tables, formulas, stamps และ mixed text-image layouts</td></tr><tr><td>Multiple services</td><td>รองรับ Baidu PaddleOCR, Microsoft Azure Vision และ Google Vision</td></tr><tr><td>Copy results</td><td>Copy recognized text หลัง processing</td></tr><tr><td>Export files</td><td>Export <code>Markdown</code>, <code>PDF</code> และ <code>Word</code></td></tr><tr><td>Batch packaging</td><td>หลัง recognize หลาย files สามารถ download results เป็น package</td></tr></tbody></table><h2 id="configure-ocr-services-ก่อน" tabindex="-1">Configure OCR Services ก่อน <a class="header-anchor" href="#configure-ocr-services-ก่อน" aria-label="Permalink to &quot;Configure OCR Services ก่อน&quot;">​</a></h2><p>เปิด:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+t+'" alt="IP geolocation and OCR" loading="lazy"></p><p>กรอก credentials สำหรับ services ที่ต้องการใช้:</p><table tabindex="0"><thead><tr><th>Service</th><th>What To Enter</th><th>Best For</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Recommended first choice เหมาะกับ documents, images, tables และ mixed layouts</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> และ <code>Azure Vision API Key</code></td><td>เหมาะถ้าใช้ Microsoft cloud services อยู่แล้ว</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code> ส่วน service account <code>JSON</code> ใช้เฉพาะ quota query</td><td>เหมาะถ้าใช้ Google Cloud services</td></tr></tbody></table><p>กรอก credentials แล้ว save</p><p>สำหรับ initial testing configure service เดียวก็พอ ไม่จำเป็นต้องครบทั้งสาม</p><h2 id="google-vision-setup" tabindex="-1">Google Vision Setup <a class="header-anchor" href="#google-vision-setup" aria-label="Permalink to &quot;Google Vision Setup&quot;">​</a></h2><p>Google setup มีสองส่วน:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Requirement</th></tr></thead><tbody><tr><td>ใช้ OCR</td><td>Enable <code>Cloud Vision API</code> แล้วสร้าง <code>API Key</code></td></tr><tr><td>Query usage</td><td>สร้าง service account, grant <code>Monitoring Viewer</code>, แล้ว download service account <code>JSON</code></td></tr></tbody></table><p><img src="'+i+'" alt="Google API key and service account" loading="lazy"></p><h3 id="ใช้-google-สําหรับ-ocr" tabindex="-1">ใช้ Google สำหรับ OCR <a class="header-anchor" href="#ใช้-google-สําหรับ-ocr" aria-label="Permalink to &quot;ใช้ Google สำหรับ OCR&quot;">​</a></h3><ol><li>เปิด Google Cloud Console</li><li>ไปที่ <code>APIs &amp; Services</code></li><li>เปิด <code>Library</code>, search <code>Cloud Vision API</code> แล้ว enable</li><li>กลับไปที่ <code>Credentials</code></li><li>Create <code>API Key</code></li><li>เปิด API Key แล้ว copy</li><li>Paste ใน <code>Google Vision API Key</code> ของ ImgBed</li><li>Save</li></ol><p>จากนั้นเลือก Google Vision ใน OCR dialog ได้</p><h3 id="query-google-usage" tabindex="-1">Query Google Usage <a class="header-anchor" href="#query-google-usage" aria-label="Permalink to &quot;Query Google Usage&quot;">​</a></h3><p>Quota query ไม่ required สำหรับ recognition</p><p>ใช้แสดงคร่าว ๆ ว่า Google Vision calls ถูกใช้ไปเท่าไรใน 30 วันที่ผ่านมา</p><ol><li>ใน Google Cloud Console เปิด <code>IAM &amp; Admin</code></li><li>เปิด <code>Service Accounts</code></li><li>สร้าง service account เช่น <code>vision-monitor</code></li><li>Grant role <code>Monitoring Viewer</code></li><li>เปิด service account details แล้ว create key</li><li>เลือก <code>JSON</code></li><li>Download generated JSON file</li><li>กลับไป ImgBed แล้ว import ใน service account <code>JSON</code> (optional)</li><li>หลัง import สำเร็จ คลิก quota query</li></ol><p>หลัง import ImgBed จะแสดง project name ที่เป็นเจ้าของ service account เมื่อ query usage ImgBed จะอ่าน Google monitoring data แล้วแสดง call count ของเดือนนี้</p><p>สรุป:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>ทำ OCR recognition</td></tr><tr><td>Service account <code>JSON</code></td><td>Query จำนวน Google Vision calls ที่ใช้</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>ให้ service account อ่าน usage data</td></tr></tbody></table><h2 id="รับ-baidu-paddleocr-token" tabindex="-1">รับ Baidu PaddleOCR Token <a class="header-anchor" href="#รับ-baidu-paddleocr-token" aria-label="Permalink to &quot;รับ Baidu PaddleOCR Token&quot;">​</a></h2><p>Baidu PaddleOCR ต้องใช้ access token</p><p><img src="'+o+'" alt="Get PaddleOCR token" loading="lazy"></p><p>เปิด <code>API</code> call window ในหน้า Baidu PaddleOCR คลิกเพื่อรับ token แล้ว copy</p><p>กลับไป ImgBed paste ใน <code>PaddleOCR Token</code> แล้ว save</p><h2 id="เริ่ม-recognition" tabindex="-1">เริ่ม Recognition <a class="header-anchor" href="#เริ่ม-recognition" aria-label="Permalink to &quot;เริ่ม Recognition&quot;">​</a></h2><p>ใน File Management เลือก image หรือ document screenshot แล้วคลิก <code>OCR</code></p><p><img src="'+a+'" alt="OCR recognition" loading="lazy"></p><p>ใน dialog เลือก recognition service และ model</p><p>Common PaddleOCR model choices:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Recommended default เหมาะกับ documents, tables, formulas, stamps และ mixed layouts</td></tr><tr><td><code>PP-OCRv5</code></td><td>Simple images, ordinary text และ lightweight recognition</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Multilingual, complex images และ chart-like content</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>Document pages ที่ซับซ้อนกว่า และ layout recovery</td></tr></tbody></table><p>ถ้าไม่แน่ใจ เริ่มด้วย <code>PP-StructureV3</code></p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Orientation correction</td><td>ใช้เมื่อ image หมุนหรือเอียง</td></tr><tr><td>Document flattening</td><td>ใช้กับ photographed documents ที่มี curvature หรือ tilt</td></tr><tr><td>Layout detection</td><td>ใช้เมื่อต้องการ preserve headings, paragraphs, tables และ image structure</td></tr><tr><td>Chart recognition</td><td>ใช้เมื่อ image มี charts หรือ structures ซับซ้อน</td></tr><tr><td>Beautify <code>Markdown</code></td><td>ทำให้ exported Markdown อ่านง่ายขึ้น</td></tr></tbody></table><p>สำหรับ regular screenshots ให้ใช้ options น้อยที่สุด สำหรับ document scans ให้ enable document-related options มากขึ้น</p><h2 id="ดู-results" tabindex="-1">ดู Results <a class="header-anchor" href="#ดู-results" aria-label="Permalink to &quot;ดู Results&quot;">​</a></h2><p>หลัง recognition เสร็จ dialog จะแสดง result</p><p>คุณ copy ได้ทันทีหรือเลือก export formats</p><p><img src="'+d+'" alt="PDF recognition" loading="lazy"></p><p>สำหรับ document pages, exported <code>PDF</code> สามารถ preserve page appearance พร้อมให้ text searchable เหมาะกับ archiving scans และค้นหา content ภายหลัง</p><h2 id="เลือก-export-format" tabindex="-1">เลือก Export Format <a class="header-anchor" href="#เลือก-export-format" aria-label="Permalink to &quot;เลือก Export Format&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Best For</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Notes, documentation systems และการ edit ภายหลัง</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Preserve page appearance และ scanned document results</td></tr><tr><td><code>Word (.docx)</code></td><td>Layout editing, text modification และส่งต่อให้คนอื่น</td></tr><tr><td>Export all</td><td>Save multiple formats และ original image เหมาะกับ archives สำคัญ</td></tr></tbody></table><p>ถ้าต้องการแค่ text ให้ export Markdown</p><p>ถ้าต้องการ page appearance ให้ใช้ PDF หรือ Word</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>Exported Word documents เปิดและ edit ด้วย office software ได้</p><p><img src="'+r+`" alt="Word result" loading="lazy"></p><p>Documents บางแบบมี recognized images, headings และ paragraphs ใน Word output</p><p>Recognition quality ขึ้นกับ original image clarity, model choice และ document complexity</p><h2 id="file-types-ที่เหมาะกับ-ocr" tabindex="-1">File Types ที่เหมาะกับ OCR <a class="header-anchor" href="#file-types-ที่เหมาะกับ-ocr" aria-label="Permalink to &quot;File Types ที่เหมาะกับ OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>Recommendation</th></tr></thead><tbody><tr><td>Clear screenshots</td><td>Recognize ได้โดยตรง</td></tr><tr><td>Scans</td><td>Prefer <code>PP-StructureV3</code></td></tr><tr><td>Photographed documents</td><td>Enable orientation correction และ document flattening</td></tr><tr><td>Tables, formulas, stamps</td><td>Prefer structured models</td></tr><tr><td>Simple short text images</td><td><code>PP-OCRv5</code> มักพอ</td></tr></tbody></table><p>Images ที่ชัดและ text ตรงจะให้ results ดีกว่า</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Recognition fails</td><td>ตรวจว่า service token หรือ key ถูก save แล้ว</td></tr><tr><td>Recognition slow</td><td>Complex documents และ large images ใช้เวลานานกว่า</td></tr><tr><td>Table incomplete</td><td>ลอง structured model</td></tr><tr><td>Text มี mistakes</td><td>Blur, glare และ skew เพิ่ม recognition errors ลอง image ที่ชัดกว่า</td></tr><tr><td>Word output มี images จำนวนมาก</td><td>Structured models อาจ preserve recognized images บางส่วน เป็นเรื่องปกติ</td></tr></tbody></table><h3 id="google-quota-query-fails" tabindex="-1">Google Quota Query Fails <a class="header-anchor" href="#google-quota-query-fails" aria-label="Permalink to &quot;Google Quota Query Fails&quot;">​</a></h3><p>ตรวจว่า:</p><ol><li>Import service account <code>JSON</code> แล้ว</li><li>Service account มี role <code>Monitoring Viewer</code></li><li>Project enable <code>Cloud Vision API</code></li></ol><p>ถ้าต้องการแค่ OCR ไม่ต้อง query usage สามารถไม่ใส่ service account JSON และกรอกแค่ <code>Google Vision API Key</code></p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>เปิด System Settings</span></span>
<span class="line"><span>-&gt; เปิด Other Settings</span></span>
<span class="line"><span>-&gt; กรอก OCR service credentials</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; กลับไป File Management</span></span>
<span class="line"><span>-&gt; เลือก file แล้วคลิก OCR</span></span>
<span class="line"><span>-&gt; เลือก model</span></span>
<span class="line"><span>-&gt; รอ recognition</span></span>
<span class="line"><span>-&gt; Copy results หรือ export Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const v=s(p,[["render",u]]);export{f as __pageData,v as default};
